// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract StorageReader {
    uint256 public slot0;           // slot 0
    uint256 private slot1;          // slot 1
    mapping(uint256 => uint256) private slot2Map; // slot 2

    function setValues(uint256 a, uint256 b, uint256 key, uint256 mapVal) external {
        slot0 = a;
        slot1 = b;
        slot2Map[key] = mapVal;
    }

    function readSlot0Assembly() external view returns (uint256 result) {
        assembly {
            [[SLOT load0]]
        }
    }

    function readSlot1Assembly() external view returns (uint256 result) {
        assembly {
            [[SLOT load1]]
        }
    }

    function readMapSlotAssembly(uint256 key) external view returns (uint256 result) {
        bytes32 slot = [[SLOT map_slot]];
        assembly {
            result := sload(slot)
        }
    }
}
